  ('pukao-7fec267e-moex-00386', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '裁罰所適用之法規中「公告」內容之變更，應如何適用行政罰法之規定？', '["係屬事實上之變更，並非處罰法律有所變更，故無從新從輕原則適用", "係屬事實及處罰法律皆有所變更，故有從新從輕原則適用", "係屬處罰法律有所變更，故有從新從輕原則適用", "係屬事實及處罰法律皆未有變更，故無從新從輕原則適用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00387', 'pukao-7fec267e', 'pukao-7fec267e-moex-112-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '行政罰法有關單一行為及數行為之處罰規定，下列敘述何者錯誤？', '["數行為違反同一或不同行政法上義務之規定者，應為整體性評價處罰之", "一行為違反數個行政法上義務規定而應處罰鍰者，依法定罰鍰額最高之規定裁處", "一行為違反社會秩序維護法及其他行政法上義務規定而應受處罰，如已裁處拘留者，不再受罰鍰之處罰", "一行為同時觸犯刑事法律及違反行政法上義務規定者，原則上依刑事法律處罰之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:15+00:00", "source_pdf_sha1": "84d04be667ac", "answer_pdf_sha1": "388087fe85dd", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "401", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
